#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        if(N==1 || N%2==0) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

