code.Python3:
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    out = []
    for i in range(1, t+1):
        n = int(data[i])
        out.append('YES' if n == 1 or n % 2 == 0 else 'NO')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

